package com.apex.vapp;

import android.app.Application;
import android.content.Context;
import android.content.SharedPreferences;
import android.util.Log;

import androidx.appcompat.app.AppCompatDelegate;

import net_62v.external.IMundoProcessCallback;
import net_62v.external.MetaActivationManager;
import net_62v.external.MetaCore;

import org.lsposed.lsparanoid.Obfuscate;

@Obfuscate
public class App extends Application implements IMundoProcessCallback {

    private static final String LICENSE_KEY = "LABD0WSED5WMJHXNFBR4";
    private static final String TAG = "AppMundo";
    public static App gApp;

    public static App getApp() {
        return gApp;
    }

    @Override
    protected void attachBaseContext(Context base) {
        super.attachBaseContext(base);

        try {
            MetaCore.attachMetaBase(base);
        } catch (Throwable t) {
            Log.e(TAG, "Failed to attach MetaBase", t);
        }
    }

    @Override
    public void onCreate() {
        super.onCreate();
        gApp = this;
        Log.i(TAG, "Application onCreate started");

        SharedPreferences prefs = getSharedPreferences("ThemePrefs", MODE_PRIVATE);
        boolean isDark = prefs.getBoolean("isDarkTheme", true);
        AppCompatDelegate.setDefaultNightMode(isDark ? AppCompatDelegate.MODE_NIGHT_YES : AppCompatDelegate.MODE_NIGHT_NO);

        try {
            MetaCore.setProcessLifecycleCallback(this);
            MetaActivationManager.activateSdk(LICENSE_KEY);
        } catch (Throwable exception) {
            Log.e(TAG, "Activation Exception", exception);
        }
    }

    @Override
    public void onCreate(String packageName, String processName) {
        Log.d(TAG, "Mundo Process Created: " + packageName + " | " + processName);
    }

    @Override
    public void onInitialized() {
        try {
            boolean isActivated = MetaActivationManager.getActivationStatus();
            String message = MetaActivationManager.getActivationMessage();
            if (isActivated) {
                Log.i(TAG, "✅ SDK Active! Server message: " + message);
            } else {
                Log.e(TAG, "❌ SDK NOT ACTIVE! Server message: " + message);
            }
        } catch (Throwable t) {
            Log.e(TAG, "Error checking activation status", t);
        }
    }
}